(function buildFixtures() {
  const fixtures = [];
  let id = 1, venueIdx = 0;
  for (const [g, teams] of Object.entries(window.GROUPS)) {
    for (let md = 0; md < 3; md++) {
      const [a, b, c, d] = MD_PATTERN[md];
      const pairs = [[a, b], [c, d]];
      for (let p = 0; p < pairs.length; p++) {
        const [hi, ai] = pairs[p];
        fixtures.push({
          id: id++,
          group: g,
          matchday: md + 1,
          date: GROUP_DATES[g][md],
          time: KICKOFFS[(id + p) % KICKOFFS.length],
          venue: VENUES[venueIdx % VENUES.length],
          home: teams[hi],
          away: teams[ai],
        });
        venueIdx++;
      }
    }
  }
  // Group A's opening match is fixed at Mexico City Stadium on June 11.
  const opener = fixtures.find(f => f.group === "A" && f.matchday === 1 && f.home.code === "MEX");
  if (opener) opener.venue = "Mexico City Stadium";
  window.FIXTURES = fixtures;
})();

