// ——— Sanity validators ———
(function validate() {
  console.assert(window.NATIONS.length === 48, "nations count");
  console.assert(window.FIXTURES.length === 72, "fixtures count");
  for (const [g, teams] of Object.entries(window.GROUPS)) {
    console.assert(teams.length === 4, `group ${g} size`);
    const played = {};
    teams.forEach(t => played[t.code] = 0);
    window.FIXTURES.filter(f => f.group === g).forEach(f => {
      played[f.home.code]++; played[f.away.code]++;
    });
    Object.values(played).forEach(n => console.assert(n === 3, `group ${g} plays 3`));
  }
})();
